        @mcp.tool()
        async def tex_render_math_to_png(
            formula: str,
            output_filename: str | None = None,
            resolution: int | None = None,
            scale: int | None = None,
            preamble: str | None = None,
        ) -> dict:
            """
            Render a LaTeX math formula to a PNG image using Aspose.Tex.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                formula: LaTeX math formula to render.
                output_filename: Bare filename for the PNG to create. If omitted, a temporary name is generated.
                resolution: Image resolution in DPI (default 150).
                scale: Scale factor (default 3000, i.e., 300%).
                preamble: Custom LaTeX preamble for the formula.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str   # bare name of the generated PNG
                }
        
            Raises:
                FileNotFoundError: If a required input file cannot be found (not applicable here).
                OSError: If the platform is not supported.
                Exception: Any unexpected error from Aspose.Tex.
        
            Example:
                result = await tex_render_math_to_png(
                    formula=r"\\int_0^\\infty e^{-x^2}\\,dx",
                    output_filename="integral.png",
                    resolution=200,
                    scale=3500,
                    preamble=r"\\usepackage{amsmath}"
                )
            """
            # ----------------------------------------------------------------------
            # Validate and resolve output filename (first operation before any Aspose import)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
            import sys
        
            logger = logging.getLogger(__name__)
        
            # Platform check (Aspose.Tex is Windows‑only in many deployments)
            if not sys.platform.startswith("win"):
                return {
                    "status": "error",
                    "message": "tex_render_math_to_png is only supported on Windows platforms.",
                    "output_filename": ""
                }
        
            # Sanitize output filename if provided
            if output_filename is not None:
                output_filename = Path(output_filename.strip().replace("\x00", "")).name
                resolved_output = get_safe_path(output_filename)
            else:
                # Generate a temporary safe filename
                temp_path = temp_output_path("aspose_tex_result", ".png")
                resolved_output = str(temp_path)
                output_filename = Path(resolved_output).name
        
            # Ensure the target directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Aspose.Tex rendering
            # ----------------------------------------------------------------------
            try:
                # Lazy import of Aspose libraries
                from aspose.tex.features import PngMathRenderer, PngMathRendererOptions
                from aspose.pydrawing import Color
                from io import BytesIO
        
                # Prepare renderer options
                opts = PngMathRendererOptions()
                opts.resolution = resolution if resolution is not None else 150
                opts.scale = scale if scale is not None else 3000
                if preamble is not None:
                    opts.preamble = preamble
                opts.text_color = Color.black
                opts.background_color = Color.white
                opts.log_stream = BytesIO()
                opts.show_terminal = False
        
                # Perform rendering
                with open(resolved_output, "wb") as stream:
                    PngMathRenderer().render(formula, stream, opts)
        
                return {
                    "status": "success",
                    "message": "Formula rendered successfully.",
                    "output_filename": output_filename,
                }
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Error rendering LaTeX formula to PNG")
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                }

